fn pro_v4_root_pool_board_features(
    before_game: &MonsGame,
    after_game: &MonsGame,
    perspective: Color,
) -> ProV4RootPoolBoardFeatures {
    let before = pro_v4_root_pool_board_posture(before_game, perspective);
    let after = pro_v4_root_pool_board_posture(after_game, perspective);
    ProV4RootPoolBoardFeatures {
        post_high_value_custody: pro_v4_root_pool_custody_bucket(
            after.high_value_own_carrier,
            after.high_value_opp_carrier,
            after.high_value_free,
            after.high_value_total,
        ),
        post_high_value_delta: pro_v4_root_pool_custody_delta_bucket(
            ProV4RootPoolCustodyCounts {
                own_carrier: before.high_value_own_carrier,
                opp_carrier: before.high_value_opp_carrier,
                free: before.high_value_free,
                total: before.high_value_total,
            },
            ProV4RootPoolCustodyCounts {
                own_carrier: after.high_value_own_carrier,
                opp_carrier: after.high_value_opp_carrier,
                free: after.high_value_free,
                total: after.high_value_total,
            },
        ),
        post_own_regular_custody: pro_v4_root_pool_custody_bucket(
            after.own_regular_own_carrier,
            after.own_regular_opp_carrier,
            after.own_regular_free,
            after.own_regular_total,
        ),
        post_own_regular_delta: pro_v4_root_pool_custody_delta_bucket(
            ProV4RootPoolCustodyCounts {
                own_carrier: before.own_regular_own_carrier,
                opp_carrier: before.own_regular_opp_carrier,
                free: before.own_regular_free,
                total: before.own_regular_total,
            },
            ProV4RootPoolCustodyCounts {
                own_carrier: after.own_regular_own_carrier,
                opp_carrier: after.own_regular_opp_carrier,
                free: after.own_regular_free,
                total: after.own_regular_total,
            },
        ),
        post_mon_material: pro_v4_root_pool_mon_material_bucket(&after),
        post_mon_material_delta: pro_v4_root_pool_mon_material_delta_bucket(&before, &after),
        post_cooldown_tempo: pro_v4_root_pool_cooldown_tempo_bucket(&after),
        post_cooldown_tempo_delta: pro_v4_root_pool_cooldown_tempo_delta_bucket(&before, &after),
    }
}

fn pro_v4_root_pool_mana_identity_profile_counts_mut(
    posture: &mut ProV4RootPoolManaIdentityProfilePosture,
    mana: Mana,
    perspective: Color,
) -> &mut ProV4RootPoolManaIdentityProfileCounts {
    match mana {
        Mana::Supermana => &mut posture.supermana,
        Mana::Regular(color) if color == perspective => &mut posture.own_regular,
        Mana::Regular(_) => &mut posture.opp_regular,
    }
}

fn pro_v4_root_pool_mana_identity_profile_posture(
    game: &MonsGame,
    perspective: Color,
) -> ProV4RootPoolManaIdentityProfilePosture {
    let mut posture = ProV4RootPoolManaIdentityProfilePosture::default();
    for (_, item) in game.board.occupied() {
        let Some(mana) = item.mana().copied() else {
            continue;
        };
        let counts =
            pro_v4_root_pool_mana_identity_profile_counts_mut(&mut posture, mana, perspective);
        let Some(mon) = item.mon() else {
            counts.free += 1;
            continue;
        };
        if mon.color == perspective {
            counts.own_carrier += 1;
            counts.own_drainer += usize::from(mon.kind == MonKind::Drainer);
            counts.own_spirit += usize::from(mon.kind == MonKind::Spirit);
        } else {
            counts.opp_carrier += 1;
            counts.opp_drainer += usize::from(mon.kind == MonKind::Drainer);
            counts.opp_spirit += usize::from(mon.kind == MonKind::Spirit);
        }
    }
    posture
}

