fn pro_v4_root_pool_edge_anchor_is_edge(location: Location) -> bool {
    let max = Config::MAX_LOCATION_INDEX;
    location.i == 0 || location.j == 0 || location.i == max || location.j == max
}

fn pro_v4_root_pool_edge_anchor_is_corner(location: Location) -> bool {
    let max = Config::MAX_LOCATION_INDEX;
    (location.i == 0 || location.i == max) && (location.j == 0 || location.j == max)
}

fn pro_v4_root_pool_edge_anchor_is_near_edge(location: Location) -> bool {
    let max = Config::MAX_LOCATION_INDEX;
    !pro_v4_root_pool_edge_anchor_is_edge(location)
        && (location.i == 1 || location.j == 1 || location.i == max - 1 || location.j == max - 1)
}

fn pro_v4_root_pool_edge_anchor_side_mut(
    posture: &mut ProV4RootPoolEdgeAnchorPosture,
    color: Color,
    perspective: Color,
) -> &mut ProV4RootPoolEdgeAnchorSide {
    if color == perspective {
        &mut posture.own
    } else {
        &mut posture.opp
    }
}

fn pro_v4_root_pool_edge_anchor_posture(
    game: &MonsGame,
    perspective: Color,
) -> ProV4RootPoolEdgeAnchorPosture {
    let mut posture = ProV4RootPoolEdgeAnchorPosture::default();
    for (location, item) in game.board.occupied() {
        let edge = pro_v4_root_pool_edge_anchor_is_edge(location);
        let corner = pro_v4_root_pool_edge_anchor_is_corner(location);
        let near_edge = pro_v4_root_pool_edge_anchor_is_near_edge(location);

        if let Some(mon) = item.mon() {
            if mon.is_fainted() {
                continue;
            }
            let side = pro_v4_root_pool_edge_anchor_side_mut(&mut posture, mon.color, perspective);
            side.live += 1;
            side.edge += usize::from(edge);
            side.corner += usize::from(corner);
            side.near_edge += usize::from(near_edge);
            side.center += usize::from(!edge && !near_edge);
            if edge {
                side.drainer_edge += usize::from(mon.kind == MonKind::Drainer);
                side.spirit_edge += usize::from(mon.kind == MonKind::Spirit);
                side.high_value_edge += item.mana().copied().map_or(0, |mana| {
                    usize::from(pro_v4_root_pool_is_high_value_mana(mana, perspective))
                });
                side.own_regular_edge += item.mana().copied().map_or(0, |mana| {
                    usize::from(pro_v4_root_pool_is_own_regular_mana(mana, perspective))
                });
                side.consumable_edge += usize::from(item.consumable().is_some());
            }
            continue;
        }

        if edge {
            if let Some(mana) = item.mana().copied() {
                posture.free_high_edge +=
                    usize::from(pro_v4_root_pool_is_high_value_mana(mana, perspective));
                posture.free_own_regular_edge +=
                    usize::from(pro_v4_root_pool_is_own_regular_mana(mana, perspective));
                posture.free_opp_regular_edge += usize::from(matches!(
                    mana,
                    Mana::Regular(color) if color != perspective
                ));
            }
            posture.free_consumable_edge += usize::from(item.consumable().is_some());
        }
    }
    posture
}

