fn pro_v4_root_pool_objective_control_maps(
    game: &MonsGame,
    perspective: Color,
) -> (
    BTreeSet<Location>,
    BTreeSet<Location>,
    BTreeSet<Location>,
    BTreeSet<Location>,
) {
    let mut own_step = BTreeSet::<Location>::new();
    let mut opp_step = BTreeSet::<Location>::new();
    let mut own_action = BTreeSet::<Location>::new();
    let mut opp_action = BTreeSet::<Location>::new();
    for (location, item) in game.board.occupied() {
        let Some(mon) = item.mon() else {
            continue;
        };
        if mon.is_fainted() {
            continue;
        }
        let (step_targets, action_targets) = if mon.color == perspective {
            (&mut own_step, &mut own_action)
        } else {
            (&mut opp_step, &mut opp_action)
        };
        pro_v4_root_pool_record_step_control(&game.board, item, location, step_targets);
        pro_v4_root_pool_record_action_control(&game.board, item, location, action_targets);
    }
    (own_step, opp_step, own_action, opp_action)
}

fn pro_v4_root_pool_objective_control_add(
    counts: &mut ProV4RootPoolObjectiveControlCounts,
    location: Location,
    own_step: &BTreeSet<Location>,
    opp_step: &BTreeSet<Location>,
    own_action: &BTreeSet<Location>,
    opp_action: &BTreeSet<Location>,
) {
    let own_step_control = own_step.contains(&location);
    let opp_step_control = opp_step.contains(&location);
    let own_action_control = own_action.contains(&location);
    let opp_action_control = opp_action.contains(&location);
    let own_any_control = own_step_control || own_action_control;
    let opp_any_control = opp_step_control || opp_action_control;
    counts.own_step += usize::from(own_step_control);
    counts.opp_step += usize::from(opp_step_control);
    counts.contested_step += usize::from(own_step_control && opp_step_control);
    counts.own_action += usize::from(own_action_control);
    counts.opp_action += usize::from(opp_action_control);
    counts.contested_action += usize::from(own_action_control && opp_action_control);
    counts.own_any += usize::from(own_any_control);
    counts.opp_any += usize::from(opp_any_control);
    counts.contested_any += usize::from(own_any_control && opp_any_control);
}

fn pro_v4_root_pool_objective_control_posture(
    game: &MonsGame,
    perspective: Color,
) -> ProV4RootPoolObjectiveControlPosture {
    if game.winner_color().is_some() {
        return ProV4RootPoolObjectiveControlPosture::default();
    }
    let mut posture = ProV4RootPoolObjectiveControlPosture::default();
    let (own_step, opp_step, own_action, opp_action) =
        pro_v4_root_pool_objective_control_maps(game, perspective);
    for (location, item) in game.board.occupied() {
        if let Some(mana) = item.mana().copied() {
            let counts =
                pro_v4_root_pool_objective_control_counts_mut(&mut posture, mana, perspective);
            pro_v4_root_pool_objective_control_add(
                counts,
                location,
                &own_step,
                &opp_step,
                &own_action,
                &opp_action,
            );
        }
        if item.consumable().is_some() {
            pro_v4_root_pool_objective_control_add(
                &mut posture.consumable,
                location,
                &own_step,
                &opp_step,
                &own_action,
                &opp_action,
            );
        }
    }
    posture
}

