fn pro_v4_root_pool_objective_square_counts_mut(
    posture: &mut ProV4RootPoolObjectiveSquarePosture,
    mana: Mana,
    perspective: Color,
) -> &mut ProV4RootPoolObjectiveSquareCounts {
    match mana {
        Mana::Supermana => &mut posture.supermana,
        Mana::Regular(color) if color == perspective => &mut posture.own_regular,
        Mana::Regular(_) => &mut posture.opp_regular,
    }
}

fn pro_v4_root_pool_objective_square_add(
    counts: &mut ProV4RootPoolObjectiveSquareCounts,
    square: Square,
    perspective: Color,
) {
    match square {
        Square::Regular => counts.regular += 1,
        Square::ManaBase { color } if color == perspective => counts.own_mana_base += 1,
        Square::ManaBase { .. } => counts.opp_mana_base += 1,
        Square::SupermanaBase => counts.super_base += 1,
        Square::ConsumableBase => counts.consumable_base += 1,
        Square::ManaPool { color } if color == perspective => counts.own_pool += 1,
        Square::ManaPool { .. } => counts.opp_pool += 1,
        Square::MonBase { color, .. } if color == perspective => counts.own_mon_base += 1,
        Square::MonBase { .. } => counts.opp_mon_base += 1,
    }
}

fn pro_v4_root_pool_objective_square_posture(
    game: &MonsGame,
    perspective: Color,
) -> ProV4RootPoolObjectiveSquarePosture {
    if game.winner_color().is_some() {
        return ProV4RootPoolObjectiveSquarePosture::default();
    }
    let mut posture = ProV4RootPoolObjectiveSquarePosture::default();
    for (location, item) in game.board.occupied() {
        let square = game.board.square(location);
        if let Some(mana) = item.mana().copied() {
            let counts =
                pro_v4_root_pool_objective_square_counts_mut(&mut posture, mana, perspective);
            pro_v4_root_pool_objective_square_add(counts, square, perspective);
        }
        if item.consumable().is_some() {
            pro_v4_root_pool_objective_square_add(&mut posture.consumable, square, perspective);
        }
    }
    posture
}

