fn pro_v4_root_pool_add_carrier_contact_counts(
    posture: &mut ProV4RootPoolCarrierContactPosture,
    own: bool,
    high_value: bool,
    contacted: bool,
    guarded: bool,
) {
    let contested = contacted && guarded;
    match (own, high_value) {
        (true, true) => {
            posture.own_high_carrier += 1;
            posture.own_high_contacted += usize::from(contacted);
            posture.own_high_guarded += usize::from(guarded);
            posture.own_high_contested += usize::from(contested);
        }
        (true, false) => {
            posture.own_regular_carrier += 1;
            posture.own_regular_contacted += usize::from(contacted);
            posture.own_regular_guarded += usize::from(guarded);
            posture.own_regular_contested += usize::from(contested);
        }
        (false, true) => {
            posture.opp_high_carrier += 1;
            posture.opp_high_contacted += usize::from(contacted);
            posture.opp_high_guarded += usize::from(guarded);
            posture.opp_high_contested += usize::from(contested);
        }
        (false, false) => {
            posture.opp_regular_carrier += 1;
            posture.opp_regular_contacted += usize::from(contacted);
            posture.opp_regular_guarded += usize::from(guarded);
            posture.opp_regular_contested += usize::from(contested);
        }
    }
}

fn pro_v4_root_pool_carrier_contact_posture(
    game: &MonsGame,
    perspective: Color,
) -> ProV4RootPoolCarrierContactPosture {
    if game.winner_color().is_some() {
        return ProV4RootPoolCarrierContactPosture::default();
    }
    let mut posture = ProV4RootPoolCarrierContactPosture::default();
    for (location, item) in game.board.occupied() {
        let Item::MonWithMana { mon, mana } = item else {
            continue;
        };
        if mon.is_fainted() {
            continue;
        }
        let guarded = pro_v4_root_pool_adjacent_live_mon_count(game, location, mon.color) > 0;
        let contacted =
            pro_v4_root_pool_adjacent_live_mon_count(game, location, mon.color.other()) > 0;
        pro_v4_root_pool_add_carrier_contact_counts(
            &mut posture,
            mon.color == perspective,
            pro_v4_root_pool_is_carrier_high_value_mana(*mana, mon.color),
            contacted,
            guarded,
        );
    }
    posture
}

