fn pro_v4_root_pool_potion_stock_posture(
    game: &MonsGame,
    perspective: Color,
) -> ProV4RootPoolPotionStockPosture {
    if game.winner_color().is_some() {
        return ProV4RootPoolPotionStockPosture::default();
    }
    let own_stock = match perspective {
        Color::White => game.white_potions_count,
        Color::Black => game.black_potions_count,
    }
    .max(0) as usize;
    let opp_stock = match perspective.other() {
        Color::White => game.white_potions_count,
        Color::Black => game.black_potions_count,
    }
    .max(0) as usize;
    let active_action = game.player_can_use_action();
    let active_potion_extension = !game.is_first_turn()
        && game.player_potions_count() > 0
        && game.actions_used_count >= Config::ACTIONS_PER_TURN;
    let mut posture = ProV4RootPoolPotionStockPosture {
        own_stock,
        opp_stock,
        ..ProV4RootPoolPotionStockPosture::default()
    };
    if game.active_color == perspective {
        posture.own_active_action = active_action;
        posture.own_potion_extension = active_potion_extension;
    } else {
        posture.opp_active_action = active_action;
        posture.opp_potion_extension = active_potion_extension;
    }
    posture
}

