    ProV4RootPoolActionThreatFeatures {
        post_action_threat: pro_v4_root_pool_action_threat_bucket(after_game, &after, perspective),
        post_action_threat_delta: pro_v4_root_pool_action_threat_delta_bucket(&before, &after),
    }
