fn pro_v4_root_pool_action_counter_reaches_actor(
    board: &Board,
    target_mon: Mon,
    target_location: Location,
    actor_location: Location,
) -> bool {
    match target_mon.kind {
        MonKind::Mystic => target_location
            .reachable_by_mystic_action_ref()
            .contains(&actor_location),
        MonKind::Demon => {
            if !target_location
                .reachable_by_demon_action_ref()
                .contains(&actor_location)
            {
                return false;
            }
            let between = target_location.location_between(&actor_location);
            board.item(between).is_none()
                && !matches!(
                    board.square(between),
                    Square::SupermanaBase | Square::MonBase { .. }
                )
        }
        MonKind::Spirit => target_location
            .reachable_by_spirit_action_ref()
            .contains(&actor_location),
        MonKind::Angel | MonKind::Drainer => false,
    }
}

fn pro_v4_root_pool_add_action_counter_profile_target(
    posture: &mut ProV4RootPoolActionCounterProfilePosture,
    perspective: Color,
    game: &MonsGame,
    actor_color: Color,
    actor_location: Location,
    target_location: Location,
) {
    let Some(target_mon) = game
        .board
        .item(target_location)
        .and_then(Item::mon)
        .copied()
    else {
        return;
    };
    if target_mon.is_fainted() || target_mon.color == actor_color {
        return;
    }
    if pro_v4_root_pool_action_target_guarded(&game.board, target_mon.color, target_location) {
        return;
    }

    let reaches_actor = pro_v4_root_pool_action_counter_reaches_actor(
        &game.board,
        target_mon,
        target_location,
        actor_location,
    );
    let actor_guarded = reaches_actor
        && pro_v4_root_pool_action_target_guarded(&game.board, actor_color, actor_location);
    let side = pro_v4_root_pool_action_counter_profile_side_mut(posture, perspective, actor_color);
    side.target += 1;
    side.counter += usize::from(reaches_actor && !actor_guarded);
    side.guarded_counter += usize::from(actor_guarded);
    side.no_counter += usize::from(!reaches_actor);
    if reaches_actor && !actor_guarded {
        match target_mon.kind {
            MonKind::Mystic => side.mystic_counter += 1,
            MonKind::Demon => side.demon_counter += 1,
            MonKind::Spirit => side.spirit_counter += 1,
            MonKind::Angel | MonKind::Drainer => {}
        }
    }
}

