fn pro_v4_root_pool_add_action_pickup_profile_target(
    posture: &mut ProV4RootPoolActionPickupProfilePosture,
    perspective: Color,
    game: &MonsGame,
    actor_color: Color,
    target_location: Location,
) {
    let Some(target_item) = game.board.item(target_location) else {
        return;
    };
    let Some(target_mon) = target_item.mon() else {
        return;
    };
    if target_mon.is_fainted() || target_mon.color == actor_color {
        return;
    }

    let mut high_value = false;
    let mut regular = false;
    let mut supermana = false;
    let mut consumable = false;
    let mut choice = false;
    let mut bomb = false;
    let mut potion = false;
    for &to in target_location.nearby_locations_ref() {
        if !pro_v4_root_pool_mon_can_step_to(&game.board, target_item, target_location, to) {
            continue;
        }
        match game.board.item(to) {
            Some(Item::Mana { mana }) => {
                high_value |= pro_v4_root_pool_is_carrier_high_value_mana(*mana, target_mon.color);
                regular |= pro_v4_root_pool_is_carrier_regular_mana(*mana, target_mon.color);
                supermana |= matches!(mana, Mana::Supermana);
            }
            Some(Item::Consumable { consumable: item }) => {
                consumable = true;
                match item {
                    Consumable::BombOrPotion => choice = true,
                    Consumable::Bomb => bomb = true,
                    Consumable::Potion => potion = true,
                }
            }
            Some(Item::Mon { .. } | Item::MonWithMana { .. } | Item::MonWithConsumable { .. })
            | None => {}
        }
    }

    let side = pro_v4_root_pool_action_pickup_profile_side_mut(posture, perspective, actor_color);
    side.target += 1;
    side.high_value += usize::from(high_value);
    side.regular += usize::from(regular);
    side.supermana += usize::from(supermana);
    side.consumable += usize::from(consumable);
    side.choice += usize::from(choice);
    side.bomb += usize::from(bomb);
    side.potion += usize::from(potion);
    side.no_pickup += usize::from(!high_value && !regular && !supermana && !consumable);
}

fn pro_v4_root_pool_action_pickup_profile_posture(
    game: &MonsGame,
    perspective: Color,
) -> ProV4RootPoolActionPickupProfilePosture {
    if game.winner_color().is_some() {
        return ProV4RootPoolActionPickupProfilePosture::default();
    }
    let mut posture = ProV4RootPoolActionPickupProfilePosture::default();
    for (location, item) in game.board.occupied() {
        let Some(mon) = item.mon() else {
            continue;
        };
        if mon.is_fainted() || matches!(game.board.square(location), Square::MonBase { .. }) {
            continue;
        }
        match mon.kind {
            MonKind::Mystic => {
                for &target in location.reachable_by_mystic_action_ref() {
                    pro_v4_root_pool_add_action_pickup_profile_target(
                        &mut posture,
                        perspective,
                        game,
                        mon.color,
                        target,
                    );
                }
            }
            MonKind::Demon => {
                for &target in location.reachable_by_demon_action_ref() {
                    let between = location.location_between(&target);
                    if game.board.item(between).is_some()
                        || matches!(
                            game.board.square(between),
                            Square::SupermanaBase | Square::MonBase { .. }
                        )
                    {
                        continue;
                    }
                    pro_v4_root_pool_add_action_pickup_profile_target(
                        &mut posture,
                        perspective,
                        game,
                        mon.color,
                        target,
                    );
                }
            }
            MonKind::Spirit => {
                for &target in location.reachable_by_spirit_action_ref() {
                    pro_v4_root_pool_add_action_pickup_profile_target(
                        &mut posture,
                        perspective,
                        game,
                        mon.color,
                        target,
                    );
                }
            }
            MonKind::Angel | MonKind::Drainer => {}
        }
    }
    posture
}

