fn pro_v4_root_pool_action_reach_target(
    board: &Board,
    actor_color: Color,
    target: Location,
) -> ProV4RootPoolActionReachTarget {
    match board.item(target) {
        Some(Item::Mon { mon })
        | Some(Item::MonWithMana { mon, .. })
        | Some(Item::MonWithConsumable { mon, .. }) => {
            if mon.color == actor_color {
                ProV4RootPoolActionReachTarget::Ally
            } else {
                ProV4RootPoolActionReachTarget::Enemy
            }
        }
        Some(Item::Mana { .. }) | Some(Item::Consumable { .. }) => {
            ProV4RootPoolActionReachTarget::Item
        }
        None => ProV4RootPoolActionReachTarget::Empty,
    }
}

fn pro_v4_root_pool_add_action_reach_target(
    side: &mut ProV4RootPoolActionReachSide,
    target: ProV4RootPoolActionReachTarget,
) {
    side.reach += 1;
    match target {
        ProV4RootPoolActionReachTarget::Enemy => side.enemy += 1,
        ProV4RootPoolActionReachTarget::Ally => side.ally += 1,
        ProV4RootPoolActionReachTarget::Item => side.item += 1,
        ProV4RootPoolActionReachTarget::Empty => side.empty += 1,
    }
}

fn pro_v4_root_pool_add_action_reach_counts(
    posture: &mut ProV4RootPoolActionReachPosture,
    perspective: Color,
    board: &Board,
    actor_color: Color,
    mon_kind: MonKind,
    location: Location,
) {
    let side = if actor_color == perspective {
        &mut posture.own
    } else {
        &mut posture.opp
    };
    side.actors += 1;
    match mon_kind {
        MonKind::Mystic => {
            for &target in location.reachable_by_mystic_action_ref() {
                let target = pro_v4_root_pool_action_reach_target(board, actor_color, target);
                pro_v4_root_pool_add_action_reach_target(side, target);
            }
        }
        MonKind::Demon => {
            for &target in location.reachable_by_demon_action_ref() {
                let between = location.location_between(&target);
                if board.item(between).is_some()
                    || matches!(
                        board.square(between),
                        Square::SupermanaBase | Square::MonBase { .. }
                    )
                {
                    side.blocked += 1;
                    continue;
                }
                let target = pro_v4_root_pool_action_reach_target(board, actor_color, target);
                pro_v4_root_pool_add_action_reach_target(side, target);
            }
        }
        MonKind::Spirit => {
            for &target in location.reachable_by_spirit_action_ref() {
                let target = pro_v4_root_pool_action_reach_target(board, actor_color, target);
                pro_v4_root_pool_add_action_reach_target(side, target);
            }
        }
        MonKind::Angel | MonKind::Drainer => {}
    }
}

fn pro_v4_root_pool_action_reach_posture(
    game: &MonsGame,
    perspective: Color,
) -> ProV4RootPoolActionReachPosture {
    if game.winner_color().is_some() {
        return ProV4RootPoolActionReachPosture::default();
    }
    let mut posture = ProV4RootPoolActionReachPosture::default();
    for (location, item) in game.board.occupied() {
        let Some(mon) = item.mon() else {
            continue;
        };
        if mon.is_fainted() || matches!(game.board.square(location), Square::MonBase { .. }) {
            continue;
        }
        if matches!(mon.kind, MonKind::Angel | MonKind::Drainer) {
            continue;
        }
        pro_v4_root_pool_add_action_reach_counts(
            &mut posture,
            perspective,
            &game.board,
            mon.color,
            mon.kind,
            location,
        );
    }
    posture
}

